BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?part ?partName ?partType WHERE {
  ?elem vocab:NamedElement_name "APS%20Mission" .
  ?elem rdf:type vocab:block .
  ?elem vocab:Element_ownedElement ?part .
  ?part rdf:type vocab:part%20property .
  OPTIONAL { ?part vocab:NamedElement_name ?partName }
  OPTIONAL { ?part rdf:type ?partType }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?elemName ?type WHERE {
  ?elem vocab:NamedElement_qualifiedName ?qname .
  FILTER(CONTAINS(STR(?qname), "APS Mission"))
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
}
